#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_VARS 1000
#define MAX_EXPR_LENGTH 30000

// Function to calculate the expected number of evaluations
double calculate_expected_evaluations(char *expression, double *probabilities, int n) {
    double expected_evaluations = 0.0;
    // Iterate over all possible orders of evaluation
    for (int i = 0; i < (1 << n); i++) {
        double current_state = 0.0;
        // Iterate over the variables in the current order
        for (int j = 0; j < n; j++) {
            if ((i & (1 << j)) != 0) {
                current_state += probabilities[j];
            }
        }
        expected_evaluations += current_state;
    }
    return expected_evaluations / (1 << n);
}

int main() {
    int t;
    scanf("%d", &t);
    for (int i = 0; i < t; i++) {
        char expression[MAX_EXPR_LENGTH];
        fgets(expression, sizeof(expression), stdin);
        int n;
        scanf("%d", &n);
        double probabilities[n];
        for (int j = 0; j < n; j++) {
            char var_name[6];
            scanf("%s %lf", var_name, &probabilities[j]);
        }
        double expected_evaluations = calculate_expected_evaluations(expression, probabilities, n);
        printf("%.6f\n", expected_evaluations);
    }
    return 0;
}

